static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext* context)
{
    MatmulScaleResidualAddClampLogSumExpMishCustomTiling tiling;

    // x: [M, K], weight: [N, K], bias: [N]
    const auto* xShape = context->GetInputShape(0);
    const auto* wShape = context->GetInputShape(1);
    if (xShape == nullptr || wShape == nullptr) {
        return ge::GRAPH_PARAM_INVALID;
    }
    uint32_t M = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
    uint32_t K = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));
    uint32_t N = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(0));

    // UB budgeting: we do scalar-accumulated GEMM with K-tiles. Need:
    // xSeg: kTile floats
    // wSeg: kTile floats (reused per column)
    // mulTmp: kTile floats
    // reduce work: kTile floats (conservative)
    // softmax tmp later uses separate buffer on kernel side with sharedTmp
    // total bytes per row-loop ≈ 4 * kTile * 4
    uint64_t ubBytes = 0;
    auto platformInfo = context->GetPlatformInfo();
    platform_ascendc::PlatformAscendC plat(platformInfo);
    plat.GetCoreMemSize(platform_ascendc::CoreMemType::UB, ubBytes);

    const uint32_t bytesPerFloat = 4;
    uint32_t kTile = AlignDown(static_cast<uint32_t>(ubBytes / (bytesPerFloat * 4)), 256U);
    if (kTile == 0) kTile = 256;
    if (kTile > K) kTile = AlignDown(K, 256U);
    if (kTile == 0) kTile = K; // very small K

    // blocks: grid-stride over rows
    uint32_t blockDim = M;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_K(K);
    tiling.set_N(N);
    tiling.set_kTile(kTile);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    // No extra workspace requested at host tiling time.
    size_t* ws = context->GetWorkspaceSizes(1);
    ws[0] = 0;

    context->SetTilingKey(1);
    return ge::GRAPH_SUCCESS;
}

