    CopyTiling(&td, tiling);

    MatmulScaleResAddClampLSEMishCustom::KernelMatmulScaleResidualAddClampLogSumExpMishCustom op;
    op.Init(x, weight, bias, scaling, clamp_min, clamp_max, y, td);
    op.Process();
}
